type User {
  id: ID!
  name: String!
  email: String!
}

type Query {
  users: [User!]!
  user(id: ID!): User
}

const resolvers = {
  Query: {
    users: () => [],
    user: (_, { id }) => null
  }
};
module.exports = resolvers;

module.exports = {
  theme: {
    extend: {
      colors: {
        primary: '#0050cb',
        surface: '#f6f3f2'
      }
    }
  }
}
